from flask import Flask, request, jsonify
import redis
import os
import json
from cryptography.fernet import Fernet

app = Flask(__name__)

# Load Redis configuration from environment variables
REDIS_NODES = os.getenv('REDIS_NODES').split(',')
REDIS_PASSWORD = os.getenv('REDIS_PASSWORD')
SECRET_KEY = os.getenv('SECRET_KEY').encode()

# Initialize Fernet for encryption
fernet = Fernet(SECRET_KEY)

# Create Redis connections
redis_connections = [redis.StrictRedis(host=node, port=6379, password=REDIS_PASSWORD, ssl=True) for node in REDIS_NODES]

def encrypt_data(data):
    return fernet.encrypt(data.encode()).decode()

def decrypt_data(data):
    return fernet.decrypt(data.encode()).decode()

@app.route('/store', methods=['POST'])
def store_data():
    user_data = request.json
    user_id = user_data.get('user_id')
    sensitive_data = user_data.get('sensitive_data')

    if not user_id or not sensitive_data:
        return jsonify({"error": "Invalid input"}), 400

    encrypted_data = encrypt_data(sensitive_data)
    ttl = user_data.get('ttl', 3600)  # Default TTL of 1 hour

    for redis_conn in redis_connections:
        redis_conn.setex(user_id, ttl, encrypted_data)

    return jsonify({"message": "Data stored successfully"}), 201

@app.route('/retrieve/<user_id>', methods=['GET'])
def retrieve_data(user_id):
    for redis_conn in redis_connections:
        encrypted_data = redis_conn.get(user_id)
        if encrypted_data:
            decrypted_data = decrypt_data(encrypted_data.decode())
            return jsonify({"sensitive_data": decrypted_data}), 200

    return jsonify({"error": "Data not found"}), 404

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)